// // This module implements an OR gate with an enable signal. When the enable input (en) is high (1), the output (out) will be the logical OR of the two inputs (in1 and in2). If the enable signal is low (0), the output will be forced to HIGH, effectively enabling the OR operation.
module top_module(
    input in1,
    input in2,
    input en,
    output out
);assign out = (en == 1'b1) ? (in1 & in2) : 1'b0;

endmodule
